{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9: empty env vars are no longer treated as unset,
        // so GetEnvironmentVariable("MY_FLAG") returns "" instead of null.
        // Use string.IsNullOrEmpty to preserve the original "not set" logic.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (string.IsNullOrEmpty(val))
